(26, 'Tai nghe TWS Samsung Galaxy Buds3 R530N', 3, 3, 3590000, 'samsung-tainghe2.jpg', 'Thời lượng pin tai nghe:\r\nDùng 6 giờ - Sạc Hãng không công bố\r\nThời lượng pin hộp sạc:\r\nDùng 30 giờ - Sạc Hãng không công bố\r\nCổng sạc:\r\nType-C\r\nCông nghệ âm thanh:\r\nCông nghệ phát sóng Auracast\r\nÂm thanh Hi-Fi\r\nActive Noise Cancelling\r\nAdaptive EQ\r\n360 Reality Audio\r\nTương thích:\r\nAndroid\r\niOS (iPhone)\r\nWindows\r\nỨng dụng kết nối:\r\nGalaxy Wearable\r\nTiện ích:\r\nPhiên dịch trực tiếp\r\nSạc không dây\r\nTự động chuyển đổi kết nối linh hoạt (Auto Switch)\r\nChống nước IP57\r\nCó mic thoại\r\nSạc nhanh\r\n360 Reality Audio\r\nChống ồn\r\nGalaxy AI\r\nKết nối cùng lúc:\r\n1 thiết bị\r\nCông nghệ kết nối:\r\nBluetooth 5.4\r\nĐiều khiển:\r\nCảm ứng chạm/vuốt\r\nGiọng nói (Tiếng Anh, Hàn)\r\nPhím điều khiển:\r\nTăng/giảm âm lượng\r\nPhát/dừng chơi nhạc\r\nChuyển bài hát\r\nChuyển chế độ\r\nNhận/Ngắt cuộc gọi\r\nBật/Tắt chống ồn\r\nKích thước:\r\nDài 3.1 cm - Rộng 1.78 cm - Cao 1.7 cm\r\nKhối lượng:\r\n4.7 g\r\nThương hiệu của:\r\nHàn Quốc\r\nSản xuất tại:\r\nViệt Nam\r\nHãng:\r\nSamsung', 0, '2024-11-10 08:27:02');
INSERT INTO `products` (`id`, `name`, `manu_id`, `type_id`, `price`, `image`, `description`, `feature`, `created_at`) VALUES
(27, 'Samsung Galaxy Watch7 40mm dây silicone', 3, 4, 6490000, 'samsung-dongho1.jpg', 'Màn hình\r\nCông nghệ màn hình:\r\nSuper AMOLED\r\nKích thước màn hình:\r\n1.3 inch\r\nĐộ phân giải:\r\n432 x 432 pixels\r\nKích thước mặt:\r\n40 mm\r\nThiết kế\r\nChất liệu mặt:\r\nKính Sapphire\r\nChất liệu khung viền:\r\nHợp kim nhôm\r\nChất liệu dây:\r\nSilicone\r\nĐộ rộng dây:\r\n2 cm\r\nĐộ dài dây:\r\nHãng không công bố\r\nKhả năng thay dây:\r\nCó\r\nKích thước, khối lượng:\r\nDài 40.4 mm - Ngang 40.4 mm - Dày 9.7 mm - Nặng 28.9 g\r\nTiện ích\r\nMôn thể thao:\r\nĐạp xe\r\nĐi bộ\r\nYoga\r\nNhảy dây\r\nLeo núi\r\nChạy bộ\r\nBơi lội\r\nHỗ trợ nghe gọi:\r\nNghe gọi ngay trên đồng hồ\r\nTiện ích đặc biệt:\r\nMàn hình luôn hiển thị\r\nPhát hiện té ngã\r\nNghe nhạc\r\nKết nối bluetooth với tai nghe\r\nChống nước / Kháng nước:\r\nChống nước 5 ATM - ISO 22810:2010 (Tắm, bơi vùng nước nông)\r\nTheo dõi sức khoẻ:\r\nĐiện tâm đồ (chỉ hỗ trợ khi kết nối với điện thoại Samsung)\r\nĐo nồng độ oxy (SpO2)\r\nĐo huyết áp (chỉ hỗ trợ khi kết nối với điện thoại Samsung)\r\nTheo dõi chỉ số AGEs\r\nPhân tích thành phần cơ thể\r\nPhát hiện chứng ngưng thở khi ngủ\r\nChấm điểm giấc ngủ\r\nHuấn luyện viên giấc ngủ (Sleep Coaching)\r\nCá nhân hoá vùng nhịp tim (Personalized HR Zone)\r\nTính quãng đường chạy\r\nTính lượng calories tiêu thụ\r\nTheo dõi giấc ngủ\r\nTheo dõi mức độ stress\r\nTheo dõi chu kỳ kinh nguyệt\r\nNhắc nhở nhịp tim cao, thấp\r\nĐo nhịp tim\r\nĐếm số bước chân\r\nTiện ích khác:\r\nTìm đồng hồ\r\nMàn hình cảm ứng\r\nChứng nhận độ bền MIL-STD-810H\r\nĐiều khiển chụp ảnh\r\nĐiều khiển chơi nhạc\r\nTừ chối cuộc gọi\r\nTìm điện thoại\r\nTrả lời nhanh tin nhắn có sẵn\r\nThay mặt đồng hồ\r\nDự báo thời tiết\r\nBáo thức\r\nĐiểm số năng lượng\r\nTải ứng dụng từ Google Play (Spotify, Maps, Zalo, Messenger,...)\r\nTrợ lý sống khỏe (Wellness Tips)\r\nQuản lý tiến độ tập luyện (Race)\r\nNhắc nhở uống thuốc\r\nKhóa dưới nước\r\nGợi ý trả lời tin nhắn bằng AI\r\nDouble Pinch (Chụm 2 lần)\r\nChỉ số phân tích chạy bộ nâng cao (Advanced Running Metrics)\r\nVí điện tử Samsung Wallet\r\nLoa và mic tích hợp\r\nHiển thị thông báo:\r\nLine\r\nMessenger (Facebook)\r\nZalo\r\nTin nhắn\r\nCuộc gọi\r\nPin\r\nThời gian sử dụng pin:\r\nKhoảng 40 giờ (Khi tắt Always-On-Display)\r\nThời gian sạc:\r\nKhoảng 1.2 giờ\r\nDung lượng pin:\r\n425 mAh\r\nCổng sạc:\r\nĐế sạc nam châm\r\nCấu hình & Kết nối\r\nCPU:\r\nExynos W1000\r\nBộ nhớ trong:\r\n32 GB\r\nHệ điều hành:\r\nWear OS được tùy biến bởi Samsung\r\nKết nối được với hệ điều hành:\r\nAndroid 11 trở lên dùng Google Mobile Service\r\nỨng dụng quản lý:\r\nGalaxy Wearable\r\nSamsung Health\r\nKết nối:\r\nBluetooth v5.3\r\nNFC\r\nWifi\r\nCảm biến:\r\nCảm biến ánh sáng môi trường\r\nSamsung BioActive thế hệ 2 (Cảm biến 3 trong 1)\r\nKhí áp kế\r\nCảm biến nhiệt độ hồng ngoại\r\nCảm biến địa từ\r\nCon quay hồi chuyển\r\nGia tốc kế\r\nĐịnh vị:\r\nBeidou\r\nGLONASS\r\nGPS\r\nBăng tần kép (L1 và L5)\r\nGalileo\r\nThông tin khác\r\nThời gian ra mắt:\r\n07/2024\r\nNgôn ngữ:\r\nTiếng Trung\r\nTiếng Việt\r\nTiếng Anh\r\nHãng:\r\nSamsung.', 0, '2024-11-10 08:27:02'),
