(40, 'PC Gaming MyGear x Asus GR701 ROG Z790 BTF Intel I7 14700K | Ram 32GB | 1TB SSD | RTX 4090', 4, 5, 34890000, 'asus-pc2.jpg', 'Loại Linh Kiện\r\n\r\nTên Linh Kiện\r\n\r\nBảo Hành\r\n\r\nBo mạch chủ\r\n\r\nBo Mạch Chủ Mainboard ASUS ROG Maximus Z790 HERO BTF WIFI 7.\r\n\r\n60 tháng \r\n\r\nBộ vi xử lý\r\n\r\nCPU Intel Core I7 14700K\r\n\r\n36 tháng \r\n\r\nCard màn hình\r\n\r\nCard Màn Hình ASUS ROG Strix GeForce RTX™ 4090 BTF 24GB GDDR6X\r\n\r\n60 tháng \r\n\r\nBộ nhớ RAM\r\n\r\nBộ Nhớ Ram PC Adata XPG Lancer RGB ROG 32GB (2x16GB) DDR5 6600MHz	\r\n36 tháng \r\n\r\nỔ cứng SSD\r\n\r\nỔ Cứng SSD Lexar NM790 M.2 2280 NVME 1TB GEN 4 (7400MB/s)\r\n\r\n60 tháng \r\n\r\nNguồn máy tính\r\n\r\nNguồn Asus ROG Strix 1000W Gold Aura Edition\r\n\r\n120 tháng \r\n\r\nVỏ Case\r\n\r\nVỏ Case ASUS ROG Hyperion GR701 BTF Edition\r\n\r\n24 tháng\r\n\r\nTản nhiệt CPU\r\n\r\nBộ Tản Nhiệt Nước Asus ROG Ryujin III 360 ARGB\r\n\r\n72 tháng', 0, '2024-11-10 01:27:02'),
(41, 'Microsoft Lumia 950 XL', 5, 1, 590000, 'micro1.jpg', 'Cấu hình & Bộ nhớ\r\nChip xử lý (CPU):\r\nSnapdragon 810\r\nTốc độ CPU:\r\n4 nhân 1.5 GHz & 4 nhân 2.0 GHz\r\nChip đồ họa (GPU):\r\nAdreno 430\r\nRAM:\r\n3 GB\r\nDung lượng lưu trữ:\r\n32 GB\r\nDung lượng còn lại (khả dụng) khoảng:\r\nKhoảng 24.66 GB\r\nDanh bạ:\r\nKhông giới hạn\r\nCamera & Màn hình\r\nPin & Sạc\r\nDung lượng pin:\r\n3340 mAh\r\nLoại pin:\r\nLi-Ion\r\nTiện ích\r\nRadio:\r\nCó\r\nXem phim:\r\nWMV9\r\nH.264(MPEG4-AVC)\r\nMP4\r\nNghe nhạc:\r\neAAC+\r\nWMA\r\nWAV\r\nMP3\r\nKết nối\r\nSIM:\r\n1 Nano SIM\r\nWifi:\r\nWi-Fi hotspot\r\nDual-band (2.4 GHz/5 GHz)\r\nWi-Fi 802.11 a/b/g/n/ac\r\nGPS:\r\nGLONASS\r\nGPS\r\nBluetooth:\r\nCó\r\nv4.1\r\nCổng kết nối/sạc:\r\nType-C\r\nJack tai nghe:\r\n3.5 mm\r\nKết nối khác:\r\nMiracast\r\nMHL\r\nOTG\r\nThiết kế & Chất liệu\r\nThiết kế:\r\nPin rời\r\nChất liệu:\r\nKhung & Mặt lưng nhựa, nhôm\r\nKích thước, khối lượng:\r\nNặng 165 g\r\nHãng:\r\nNokia', 0, '2024-11-10 01:27:02'),
(42, 'Microsoft Lumia 53', 5, 1, 1590000, 'micro2.pjg', 'Cấu hình & Bộ nhớ\r\nChip xử lý (CPU):\r\nSnapdragon 200\r\nTốc độ CPU:\r\n1.2 GHz\r\nChip đồ họa (GPU):\r\nAdreno 302\r\nRAM:\r\nĐang cập nhật\r\nDung lượng lưu trữ:\r\n8 GB\r\nDung lượng còn lại (khả dụng) khoảng:\r\nĐang cập nhật\r\nDanh bạ:\r\nKhông giới hạn\r\nCamera & Màn hình\r\nĐộ phân giải camera sau:\r\n5 MP\r\nQuay phim camera sau:\r\nSD 480p@30fps\r\nĐộ phân giải camera trước:\r\nVGA (0.3 MP)\r\nCông nghệ màn hình:\r\nLCD\r\nĐộ phân giải màn hình:\r\nWVGA (480 x 800 Pixels)\r\nKích thước màn hình:\r\n4\"\r\nMặt kính cảm ứng:\r\nKính thường\r\nPin & Sạc\r\nDung lượng pin:\r\n1560 mAh\r\nLoại pin:\r\nLi-Ion\r\nTiện ích\r\nRadio:\r\nCó\r\nXem phim:\r\nH.264(MPEG4-AVC)\r\nMP4\r\nNghe nhạc:\r\nAAC\r\nWAV\r\nMP3\r\nKết nối\r\nMạng di động:\r\nĐang cập nhật\r\nSIM:\r\n1 Micro SIM\r\nWifi:\r\nWi-Fi hotspot\r\nWi-Fi 802.11 a/b/g/n\r\nGPS:\r\nCó\r\nBluetooth:\r\nv4.0\r\nCổng kết nối/sạc:\r\nMicro USB\r\nJack tai nghe:\r\n3.5 mm\r\nThiết kế & Chất liệu\r\nThiết kế:\r\nPin rời\r\nChất liệu:\r\nKhung & Mặt lưng nhựa\r\nKích thước, khối lượng:\r\nNặng 136.3 g\r\nHãng:\r\nNokia.', 0, '2024-11-10 01:27:02'),
(43, 'Surface Laptop 4 I7 16GB 512GB 13.5', 5, 2, 13590000, 'micro-lap1.jpg', '\r\n- CPU	 Intel® Core™ i7-1185G7\r\n- Card đồ họa	 Intel Iris Xe Graphics\r\n- Bộ nhớ trong	 512 GB SSD\r\n- RAM	 16 GB\r\n- Kích thước màn hình	13.5-inch\r\n- Độ phân giải	 2256 x 1504 pixels (201 PPI)\r\n- Trọng lượng	 1.265 kg', 0, '2024-11-10 01:27:02'),
(44, 'Surface Laptop Studio 2 13th Gen Intel Core i7, 16GB RAM, 512GB SSD NVIDIA GeForce RTX 4050', 5, 2, 52590000, 'micro-lap2.jpg', 'Kích thước	323,28 mm x 228,32 mm x 18,94 mm\r\nMàn hình	Màn hình hiển thị PixelSense Flow 14.4 inch\r\nTần số quét: 120Hz\r\nĐộ phân giải: 2400 x 1600 pixels (201 PPI)\r\nTỷ lệ khung hình 3:2\r\nTỷ lệ tương phản 1500:1\r\nCảm ứng 10 điểm chạm\r\nKính cường lực Gorilla Glass 5\r\nRam	16GB LPDDR5\r\nỔ cứng SSD	512GB SSD (có thể thay thế được)\r\nCPU	– Bộ xử lý Core™ i7-13700H thế hệ thứ 13\r\n(Được xây dựng trên nền tảng Intel Evo)\r\n– Bộ gia tốc AI Intel® Movidius™ 3700VC thế hệ thứ 3\r\nBảo mật	Windows Hello\r\nTrọng lượng	4.37 lbs (~1,98kg)\r\nBút tương thích	Surface Pen hoặc Surface Slim Pen 2\r\nThời lượng pin	Lên đến 18 giờ (theo hãng công bố ở điều kiện tiêu chuẩn)\r\nCard đồ họa	– NVIDIA® GeForce RTX™ 4050 GPU với 6GB GDDR6 vRAM\r\n(tốc độ xung nhịp: 2130 MHz, công suất đồ họa tối đa 80W)\r\nCổng kết nối	– 2 cổng USB-C Thunderbolt 4\r\n– 1 jack tai nghe 3,5 mm\r\n– 1 cổng Surface Connect\r\n– USB-A 3.1\r\n– MicroSDXC card reader\r\nPhần mềm	– Windows 11 Home\r\n– Preloaded Microsoft 365 Apps\r\n– Bản dùng thử trong 30 ngày Microsoft 365 Family\r\n– Preloaded Xbox App\r\n– Dùng thử trong 30 ngày Xbox Game Pass Ultimate\r\nCameras, video và audio	Camera trước độ phân giải 1080p\r\nMics: Dual Studio Mics with Voice Clarity\r\nAudio: Quad Omnisonic với công nghệ Dolby Atmos\r\nKết nối	Wi-Fi 6E: 802.11ax; Bluetooth 5.3\r\nChất liệu	Vỏ: Nhôm Anodized ; Màu sắc: Platinum', 0, '2024-11-10 01:27:02'),
(45, 'Tai nghe Surface Headphones kết nối không dây bluetooth', 5, 3, 4790000, 'micro-tainghe1.jpg', 'Tại sự kiện của Microsoft diễn ra vào ngày 3/10, hãng đã giới thiệu mới một sản phẩm nhận được sự quan tâm rất lớn của những người hâm mộ Surface chính là chiếc tai nghe Surface Headphone – đây là chiêc tai không dây kết nối bluetooth tốt nhất của hãng từ trước tới nay.\r\n\r\nSurface Headphone đắt tiền, nhưng đáng giá vì bạn đang nhận được nhiều hơn chỉ là một đôi tai nghe. Ngoài việc đánh giá trực tiếp các tính năng của đôi tai nghe này nó còn được so sánh đánh giá với rất nhiều các sản phẩm cùng phân khúc khác. Hãy cùng Surface Việt khám phá về chiếc tai nghe thú vị này nhé.', 0, '2024-11-10 01:27:02'),
(46, 'Tai nghe Microsoft Surface Headphones 2 kết nối không dây', 5, 3, 21990000, 'micro-tainghe2.jpg', '2 phiên bản màu sắc: Xám trắng Light Gray & Đen Matte Black\r\nTrọng lượng chỉ 0,29kg. Kiểu dáng thiết kế ôm tai. Kết nối không dây.\r\nSạc pin cổng type C chỉ mất 2h & sử dụng trong 15 – 18.5 tiếng liên tục\r\nTương thích Windows 10, 11, Android 9 or 10, iOS 12 or 13, Bluetooth 4.1, 4.2, 5.0\r\n13 chế độ lọc, khử tạp âm, tiếng ồn môi trường', 0, '2024-11-10 01:27:02'),
(47, 'Microsoft Xbox Watch', 5, 4, 7990000, 'micro-dongho1.jpg', 'Nguyên mẫu được thiết kế hình vuông bo góc, bao gồm một màn hình hiển thị 1,5 inch. Bên cạnh đó, dây đeo tay của nó cũng có thể tháo rời được giống như các loại đồng hồ thông minh hiện đại. Giao diện của thiết bị trông khá giống với giao diện của các sản phẩm đeo ngoài khác mà Microsoft đã bỏ lại; nhưng nhìn chung, trông giao diện của nó giống với giao diện của Xbox năm 2013.\r\nSản phẩm này có thể đo được các thông số sức khỏe, theo dõi GPS, có cảm biến nhịp tim, có nhiều ứng dụng cho tập luyên thể thao. Có vẻ như đối tượng khách hàng của Xbox Watch là những người yêu thích thể thao và có nhu cầu sử dụng đồng hồ như một công cụ hỗ trợ sức khỏe.', 0, '2024-11-10 01:27:02'),
(48, 'Microsoft ra mắt đồng hồ mang chủ đề Xbox, giới hạn 250 chiếc', 5, 4, 19990000, 'micro-dongho2.jpg', 'Microsoft mới đây đã bắt tay với nhà sản xuất đồng hồ Meister Clock của Mỹ, giới thiệu đồng hồ phiên bản giới hạn mang phong cách Xbox đặc trưng. Trước đó, hãng đã từng tung ra các sản phẩm thuộc chủ đề Xbox như tủ lạnh, các tay cầm chơi game có thiết kế độc đáo và khác biệt.\r\n\r\nSản phẩm chỉ giới hạn 250 chiếc, mang tông màu \'Crystal White\' thường thấy trên tay cầm Xbox và có thiết kế khá tinh tế, hút mắt. Không giống với những chiếc smartwatch hiện nay, đây là sản phẩm kết hợp giữa tính thẩm mỹ hiện đại nhưng mang trong mình chức năng của đồng hồ cổ điển.\r\n\r\nĐồng hồ Microsoft đi kèm dây đeo màu đen/trắng cho người dùng thay đổi. Điểm nhấn trên dây đeo tới từ các hoạ tiết xếp lớp địa hình, mang lại vẻ độc đáo cho đồng hồ. Bộ máy điều khiển đồng hồ là hệ thống thạch anh 3 kim của Nhật Bản, đảm bảo độ chính xác và tuổi thọ của sản phẩm.', 0, '2024-11-10 01:27:02'),
(49, 'Microsoft Surface Studio 2+ 28-inch Touchscreen All-In-One Desktop Computer, Intel Core i7-11370H 3.', 5, 5, 132269179, 'micro-pc1.jpg', '\r\nStanding screen display size	28 Inches\r\nScreen Resolution	4500 x 3000\r\nMax Screen Resolution	3840 x 2160 pixels\r\nProcessor	3 GHz core_i7\r\nRAM	32 GB DDR4\r\nHard Drive	1 TB SSD\r\nGraphics Coprocessor	Nvidia Ge Force Rtx 3060\r\nChipset Brand	NVIDIA\r\nCard Description	Dedicated\r\nGraphics Card Ram Size	6 GB\r\nWireless Type	Bluetooth, 802.11ax\r\nBrand	Microsoft\r\nSeries	Surface Studio 2+\r\nItem model number	SBG-00001\r\nHardware Platform	PC\r\nOperating System	Windows 11 Pro, Windows\r\nItem Weight	21.1 pounds\r\nProduct Dimensions	25.1 x 0.5 x 17.3 inches\r\nItem Dimensions LxWxH	25.1 x 0.5 x 17.3 inches\r\nColor	Silver\r\nProcessor Brand	Intel\r\nNumber of Processors	4\r\nComputer Memory Type	DDR4 SDRAM\r\nHard Drive Interface	Solid State', 0, '2024-11-10 01:27:02'),
(50, 'HP Pavilion TP01-4019d i5 13400/8GB/512GB/Bàn phím/Chuột/Win11 (8X3R3PA)', 5, 5, 14690000, 'micro-pc2.jpg', 'Bộ xử lý\r\nCông nghệ CPU:\r\ni5\r\nLoại CPU:\r\n13400\r\nTốc độ CPU:\r\n2.50 GHz\r\nTốc độ tối đa:\r\n4.60 GHz\r\nChipset:\r\nIntel H670\r\nBộ nhớ RAM, Ổ cứng\r\nRAM:\r\n8 GB\r\nLoại RAM:\r\nDDR4 2 khe (1 khe 8 GB + 1 khe trống)\r\nSố khe RAM:\r\n2 khe\r\nTốc độ Bus RAM:\r\n3200 MHz\r\nHỗ trợ RAM tối đa:\r\n32 GB\r\nỔ cứng:\r\n512 GB SSD\r\nChuẩn kết nối ổ cứng:\r\n1 x Hỗ trợ khe cắm HDD SATA 3.5 inch (nâng cấp lên tối đa 2 TB)\r\nĐồ họa và Âm thanh\r\nThiết kế card:\r\nCard đồ hoạ tích hợp\r\nCard màn hình:\r\nIntel UHD 730\r\nCông nghệ âm thanh:\r\nRealtek High Definition Audio\r\nCổng kết nối & tính năng mở rộng\r\nCổng kết nối - Mặt sau:\r\n4 x USB 2.0\r\n1 x LAN (RJ45)\r\n1 x HDMI\r\n1 x VGA\r\n3 x Audio jacks\r\nCổng kết nối - Mặt trước:\r\n1 x USB Type-C 3.2\r\n1 x Headphone/microphone combo\r\n4 x USB 3.2\r\nGiao tiếp mạng:\r\nWi-Fi 6(802.11ax)\r\nBluetooth 5.3\r\nKhe đọc thẻ nhớ:\r\nSD\r\nTính năng khác:\r\nĐi kèm chuột & bàn phím\r\nKích thước & khối lượng\r\nKích thước, khối lượng:\r\nDài 337.4 mm - Rộng 304 mm - Dày 155.4 mm - Nặng 5.96 kg\r\nThông tin khác\r\nBộ nguồn điện:\r\n350W\r\nHệ điều hành:\r\nWindows 11\r\nThời gian ra mắt:\r\n2023', 0, '2024-11-10 01:27:02');

